-- ============================================================
-- Этап 3 «Четыре цветные стены» (walls) проекта Homesteader's
-- Cabin — эталонный контент из ЭТАП3_Стены.md. Реальные данные:
-- длинные стены 7,32 м, короткие 3,66 м с фронтоном 45°,
-- стойки 50×150 шаг 610 мм, реальные проёмы окон/двери.
-- Цветовая маркировка стен: 🟡 передняя, 🔵 задняя, 🔴 левая,
-- 🟢 правая. Блок про обшивку и скрипт покупки бруса/окон —
-- в hint шага 5. Safety_text — у шагов подъёма (2, 3, 4).
-- Идемпотентно: пересоздаёт только шаги этапа walls (id ...313).
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000313') then
    return;
  end if;

  update stages set intro = 'Вот он, самый волнующий момент: пол готов, и теперь на нём вырастут стены. Именно сейчас плоская площадка превратится в узнаваемый дом — с окнами, дверью, комнатами. Отсюда уже видно, каким он будет.

У нас четыре стены, и чтобы ты не путался, мы дали каждой свой цвет. Так и в инструкции, и на схемах раскроя, и в жизни — покрасишь метку нужного цвета, и всё встанет на место:

🟡 Жёлтая стена — передняя, с входной дверью. Это «лицо» дома.
🔵 Синяя стена — задняя, с окнами.
🔴 Красная стена — длинная левая, с большими окнами.
🟢 Зелёная стена — длинная правая, с окнами.

Стены собираются лёжа на полу — так удобнее и безопаснее (не на высоте), а потом поднимаются и ставятся вертикально. Это старый плотницкий приём: собрал на земле как конструктор, поднял готовое.

Займёт около 7 дней — это самый большой этап. Тебе точно нужен помощник, особенно на подъёме стен. Не спеши, проверяй каждую стену на прямые углы. Готовые стены — это уже настоящий дом, в котором можно стоять.'
  where id = 'de300000-0000-4000-8000-000000000313';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000313';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    safety_text, self_check, hint, common_mistake, helpers_needed) values
  ('de300000-0000-4000-8000-000000000441',
   'de300000-0000-4000-8000-000000000313', 1,
   'Собираем каркас 🟡 жёлтой стены (передней, с дверью) — лёжа на полу',
   'Начинаем с передней стены — «лица» дома с входной дверью. Собираем её каркас прямо на полу, лёжа: это безопасно (не на высоте) и точно (всё на ровной поверхности).',
   'Купи заранее (из сметы): доски 50×150 мм (2×6) — на стойки и обвязку жёлтой стены; гвозди/саморезы 90-100 мм.',
   '["На полу выложи каркас стены плашмя: две горизонтальные доски (низ и верх стены — обвязки) и между ними вертикальные стойки.","Стойки ставь через 61 см (шаг 610 мм) — как лаги пола, под будущую обшивку. Отметь карандашом.","Оставь проём под входную дверь шириной ~91 см. Над дверью поставь усиленную балку-перемычку (несколько досок вместе) — она держит вес стены над проёмом.","Сбей каркас: прибивай стойки к обвязкам, по 2 гвоздя в каждое соединение.","Проверь диагонали каркаса — измерь крест-накрест, обе цифры равны = стена прямоугольная."]',
   '{"шуруповёрт","рулетка 10 м","угольник","карандаш","уровень"}',
   '',
   '["Каркас 🟡 жёлтой стены собран лёжа","Стойки через 61 см","Проём под дверь 91 см с усиленной перемычкой","Диагонали равны (стена прямая)"]',
   'Перемычка над дверью (её называют «ригель» или просто «балка над проёмом») нужна, чтобы вес стены не давил на дверную коробку. Без неё дверь со временем заклинит. Ставь усиленную — 2-3 доски вместе.',
   'Собрать стену без проверки диагоналей, а потом поднять кривую. Лёжа поправить легко, стоя — почти нет. Проверь, пока на полу.',
   0),
  ('de300000-0000-4000-8000-000000000442',
   'de300000-0000-4000-8000-000000000313', 2,
   'Поднимаем и закрепляем 🟡 жёлтую стену',
   'Готовый каркас поднимаем из положения «лёжа» в вертикальное и надёжно крепим к полу. Это момент, когда дом впервые встаёт в полный рост.',
   'Позови помощника (обязательно — одному опасно и тяжело!) и приготовь временные подпорки — доски-укосины, чтобы стена не упала.',
   '["Вдвоём (или втроём) поднимите каркас стены вертикально. Тяжело — но каркас без обшивки не такой уж неподъёмный.","Выставьте стену точно по краю пола, проверьте уровнем вертикаль (стена должна стоять строго прямо, не заваливаться).","Прибейте низ стены к полу (к раме пола) гвоздями каждые 40 см.","Поставь временные укосины — наклонные доски от стены к полу, чтобы стена не упала, пока не собраны остальные. Это важно для безопасности!"]',
   '{"молоток или шуруповёрт","уровень","доски-укосины"}',
   'Поднимайте стену только вдвоём или втроём — одному опасно и тяжело. Не отходи от поднятой стены, пока не прибиты укосины: порыв ветра может её уронить.',
   '["Стена поднята вдвоём/втроём (не в одиночку!)","Вертикаль по уровню","Низ прибит к полу каждые 40 см","Стоят временные укосины"]',
   'Укосина — это просто доска, приставленная наискосок от стены к полу и прибитая с двух концов. Она держит стену, как подпорка держит забор. Не пропускай — без укосин стена может упасть от ветра или толчка.',
   'Поднять стену и отойти без укосин. Порыв ветра — и стена падает (травма + сломанный каркас). Всегда подпирай сразу.',
   1),
  ('de300000-0000-4000-8000-000000000443',
   'de300000-0000-4000-8000-000000000313', 3,
   'Собираем и ставим 🔵 синюю стену (заднюю, с окнами)',
   'Напротив жёлтой ставим синюю — заднюю стену. Так же: собрали лёжа, подняли, закрепили. У неё оконные проёмы вместо двери.',
   'Купи заранее: доски 50×150 мм — на синюю стену; крепёж. Помощник и укосины — снова обязательны.',
   '["Собери каркас синей стены лёжа, стойки через 61 см.","Оставь проёмы под окна (по чертежу — окно в стене и окно в фронтоне-треугольнике наверху). Над каждым окном — перемычка.","Проверь диагонали, подними, выставь по уровню, прибей к полу.","Соедини синюю стену с жёлтой по углам — там, где они встречаются, скрути стойки вместе. Теперь две стены держат друг друга.","Оставь укосины до полной сборки."]',
   '{"шуруповёрт","уровень","рулетка 10 м","карандаш"}',
   'Поднимай только с помощником и сразу ставь укосины — стена без них может упасть от ветра.',
   '["🔵 Синяя стена собрана, проёмы окон с перемычками","Поднята, выставлена по уровню, прибита","Соединена с жёлтой стеной по углам","Укосины на месте"]',
   'Передняя и задняя стены (жёлтая и синяя) — короткие, 3,66 м, но с треугольным верхом-фронтоном под скат крыши 45°. Фронтон собирается вместе со стеной или добавляется сверху — смотри чертёж.',
   '',
   1),
  ('de300000-0000-4000-8000-000000000444',
   'de300000-0000-4000-8000-000000000313', 4,
   'Собираем и ставим 🔴 красную и 🟢 зелёную стены (длинные боковые)',
   'Теперь две длинные стены (7,32 м) — левую красную и правую зелёную. Они замкнут периметр, и дом станет закрытой коробкой.',
   'Купи заранее: доски 50×150 мм — на длинные стены (их больше, стены длинные); крепёж. Помощники и укосины обязательны.',
   '["Собери каркас 🔴 красной (левой) стены лёжа — она длинная, 7,32 м. Стойки через 61 см.","Оставь проёмы под большие окна (по чертежу — два окна ~183×91 см, панорамные снизу, плюс окно в лофте наверху). Перемычки над каждым.","Подними (тут помощник особенно нужен — стена длинная и тяжёлая), выставь, прибей, соедини с жёлтой и синей по углам.","То же для 🟢 зелёной (правой) стены — по чертежу у неё три окна поменьше.","Когда все 4 стены стоят и соединены — периметр замкнут, дом стал коробкой."]',
   '{"шуруповёрт","уровень","рулетка 10 м","карандаш"}',
   'Не геройствуй в одиночку: длинная стена 7,32 м тяжёлая, поднимайте втроём или поднимай постепенно, подставляя опоры.',
   '["🔴 Красная стена с большими окнами собрана и поставлена","🟢 Зелёная стена собрана и поставлена","Все 4 стены соединены по углам, периметр замкнут","Всё по уровню, укосины держат"]',
   'Длинную стену 7,32 м поднимать тяжело — зови двух помощников или поднимай постепенно, подставляя опоры. Не геройствуй в одиночку, это реально опасно.',
   'Экономить на стойках у больших окон. Широкое окно ослабляет стену — по бокам проёма ставь сдвоенные стойки и крепкую перемычку. Не мельчи тут.',
   2),
  ('de300000-0000-4000-8000-000000000445',
   'de300000-0000-4000-8000-000000000313', 5,
   'Связываем стены верхней обвязкой',
   'Сверху по всем стенам кладём ещё один ряд досок — верхнюю обвязку. Она связывает 4 стены в единое жёсткое кольцо, на которое потом ляжет крыша.',
   'Купи заранее: доски 50×150 мм — на верхнюю обвязку; крепёж.',
   '["По верху всех стен уложи второй ряд досок (поверх верхних обвязок каждой стены), перекрывая углы внахлёст — так стены «сшиваются» между собой.","Прибей обвязку по всей длине.","Ещё раз проверь по всему периметру: вертикали стен, прямые углы, диагонали коробки.","Теперь коробка жёсткая — можно снимать часть временных укосин (но не все, пока нет крыши)."]',
   '{"стремянка","уровень","молоток или шуруповёрт"}',
   '',
   '["Верхняя обвязка уложена по всем стенам","Углы перекрыты внахлёст","Коробка проверена на вертикаль и прямые углы"]',
   'Двойная верхняя обвязка внахлёст на углах — это то, что превращает 4 отдельные стены в прочную единую коробку. Как обруч на бочке. Не пропускай.

Про обшивку стен (когда делать). По чертежам стены обшиваются фанерой/OSB (листы 122 см, с разбежкой швов, проёмы окон вырезаются). Обшивку можно ставить двумя способами: до подъёма (лёжа на полу) — легче прибивать, но стена тяжелее для подъёма; после подъёма (стоя) — стену легче поднять, но прибивать на высоте. Для новичка с одним помощником часто проще обшить нижнюю часть лёжа, а верх — после подъёма. Обшивка добавляет жёсткости, так что не откладывай её надолго.

СКРИПТ — покупка бруса на стены и окон. На стены уходит много доски 50×150 — тут легко переплатить или взять брак, плюс окна — отдельная история. Про доску 50×150: «Сухая или естественной влажности?» — для стоек сухая лучше (не поведёт), но естественной дешевле и для стен допустима, если сразу обшить; «Сорт 1-2» — для несущих стоек; считай кубатуру при них: доска 6 м × 0,15 м × 0,05 м = 0,045 м³, значит ≈22 доски в кубе. Про окна: заказывай окна ПОСЛЕ того, как собрал проёмы — меряй реальные проёмы, а не по чертежу (могут отличаться на пару см); «Какой профиль, сколько камер?» — для жилья 3-4 камеры (тепло); проём делай на 2-3 см больше окна (на монтажную пену и регулировку). Красные флаги: доски «винтом» (скрученные), с большими сучками на месте будущей нагрузки, синева/плесень — перебирай, не бери что дают. Ориентир: доски 50×150 — основной расход этапа; окна — отдельная крупная статья, закладывай заранее.',
   '',
   0);
end
$do$;
